import java.io.*;
import java.util.*;
public class Main {
    static class State {
        int[] next = new int[2];
        int link, len;
        State() { next[0] = next[1] = -1; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            char[] A = br.readLine().trim().toCharArray();
            char[] B = br.readLine().trim().toCharArray();
            State[] st = new State[2 * N];
            for (int i = 0; i < st.length; i++) st[i] = new State();
            int sz = 1, last = 0;
            st[0].len = 0; st[0].link = -1;
            for (char ch : A) {
                int c = ch - '0';
                int cur = sz++;
                st[cur].len = st[last].len + 1;
                st[cur].next[0] = st[cur].next[1] = -1;
                int p = last;
                while (p != -1 && st[p].next[c] == -1) {
                    st[p].next[c] = cur;
                    p = st[p].link;
                }
                if (p == -1) {
                    st[cur].link = 0;
                } else {
                    int q = st[p].next[c];
                    if (st[p].len + 1 == st[q].len) {
                        st[cur].link = q;
                    } else {
                        int clone = sz++;
                        st[clone].len = st[p].len + 1;
                        st[clone].next[0] = st[q].next[0];
                        st[clone].next[1] = st[q].next[1];
                        st[clone].link = st[q].link;
                        while (p != -1 && st[p].next[c] == q) {
                            st[p].next[c] = clone;
                            p = st[p].link;
                        }
                        st[q].link = st[cur].link = clone;
                    }
                }
                last = cur;
            }
            int v = 0, l = 0, ans = 0;
            for (char ch : B) {
                int c = ch - '0';
                while (v != 0 && st[v].next[c] == -1) {
                    v = st[v].link;
                    l = st[v].len;
                }
                if (st[v].next[c] != -1) {
                    v = st[v].next[c];
                    l++;
                } else {
                    v = 0; l = 0;
                }
                if (l > ans) ans = l;
            }
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

