const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const A = input[idx++];
  const B = input[idx++];
  // suffix automaton for A
  const next = [];
  const link = [];
  const len = [];
  next.push([-1, -1]);
  link.push(-1);
  len.push(0);
  let last = 0;
  for (let ch of A) {
    const c = ch.charCodeAt(0) - 48; // 0 or 1
    const cur = next.length;
    next.push([-1, -1]);
    len.push(len[last] + 1);
    link.push(0);
    let p = last;
    while (p !== -1 && next[p][c] === -1) {
      next[p][c] = cur;
      p = link[p];
    }
    if (p === -1) {
      link[cur] = 0;
    } else {
      const q = next[p][c];
      if (len[p] + 1 === len[q]) {
        link[cur] = q;
      } else {
        const clone = next.length;
        next.push([next[q][0], next[q][1]]);
        len.push(len[p] + 1);
        link.push(link[q]);
        while (p !== -1 && next[p][c] === q) {
          next[p][c] = clone;
          p = link[p];
        }
        link[q] = link[cur] = clone;
      }
    }
    last = cur;
  }
  let v = 0, l = 0, ans = 0;
  for (let ch of B) {
    const c = ch.charCodeAt(0) - 48;
    while (v !== 0 && next[v][c] === -1) {
      v = link[v];
      l = len[v];
    }
    if (next[v][c] !== -1) {
      v = next[v][c];
      l++;
    } else {
      v = 0; l = 0;
    }
    if (l > ans) ans = l;
  }
  results.push(String(ans));
}
console.log(results.join('\n'));
